{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/RogueLikeHalf.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class RogueLikeHalf < Base\n      # ゲームシステムの識別子\n      ID = 'RogueLikeHalf'\n\n      # ゲームシステム名\n      NAME = 'ローグライクハーフ'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'ろおくらいくはあふ'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGETEXT\n        ■判定　RH+x>=t        x:技量点 t:達成値(威力)\n\n        例)RH+1>=5: ダイスを1個振って、技量点1,達成値5の結果を表示(クリティカル・ファンブルも表示)\n\n        ■D33　D33+x        x:修正値\n\n        例)D33: 3面ダイスを2個振って、その結果を表示。\n\n        ■宝物表　NTT+x     x:修正値\n      INFO_MESSAGETEXT\n\n      def initialize(command)\n        super(command)\n\n        @sort_barabara_dice = true # バラバラロール（Bコマンド）でソート有\n      end\n\n      def eval_game_system_specific_command(command)\n        resolute_action(command) ||\n          resolute_d33(command) ||\n          roll_table_command(command)\n      end\n\n      private\n\n      def with_symbol(number)\n        if number == 0\n          return \"+0\"\n        elsif number > 0\n          return \"+\#{number}\"\n        else\n          return number.to_s\n        end\n      end\n\n      # 判定ロール\n      # @param [String] command\n      # @return [Result]\n      def get_result_of_action(total, die, target)\n        if die == 6\n          return Result.critical(\"クリティカル\")\n        elsif die == 1\n          return Result.fumble(\"ファンブル\")\n        elsif total >= target\n          return Result.success(\"成功\")\n        else\n          return Result.failure(\"失敗\")\n        end\n      end\n\n      def resolute_action(command)\n        m = /RH([+-]\\d)*(>=(\\d+))?/.match(command)\n        return nil unless m\n\n        modify = m[1] ? Arithmetic.eval(m[1], @round_type) : 0\n        target = m[3].to_i\n        target = 4 if target == 0\n\n        die = @randomizer.roll_once(6)\n        die_text = die.to_s\n        total = die + modify\n\n        result = get_result_of_action(total, die, target)\n\n        command_text = \"(RH\#{with_symbol(modify)}>=\#{target})\"\n        sequence = [\n          command_text,\n          \"[\#{die_text}]\#{with_symbol(modify)}\",\n          total,\n          result.text,\n        ].compact\n\n        result.text = sequence.join(\" ＞ \")\n\n        return result\n      end\n\n      # D33ロール\n      # @param [String] command\n      # @return [Result]\n      def resolute_d33(command)\n        m = /D33([+-]\\d+)*/.match(command)\n        return nil unless m\n\n        modify = m[1] ? Arithmetic.eval(m[1], @round_type) : 0\n\n        dice = @randomizer.roll_barabara(2, 3)\n        dice_text = dice.join(\"\")\n        dice_total = dice[0] * 3 + dice[1] + modify\n        dice_total = 12 if dice_total > 12\n        dice_total = 4 if dice_total < 4\n        p = dice_total.divmod(3)\n        if p[1] == 0\n          p[0] = p[0] - 1\n          p[1] = 3\n        end\n        total = p[0] * 10 + p[1]\n\n        sequence = [\n          \"(\#{command})\",\n          dice_text,\n        ].compact\n\n        if modify != 0\n          sequence = [\n            \"(\#{command})\",\n            \"\#{dice_text}\#{with_symbol(modify)}\",\n            total,\n          ].compact\n        end\n\n        return Result.new(sequence.join(\" ＞ \"))\n      end\n\n      def roll_table_command(command)\n        command = command.upcase\n        result = []\n\n        m = /([A-Z]+)(([+]|-)(\\d+))?/.match(command)\n        return result unless m\n\n        command = m[1]\n        operator = m[3]\n        value = m[4].to_i\n\n        return get_another_table_result(command, operator, value)\n      end\n\n      def get_another_table_result(command, operator, value)\n        result = \"\"\n\n        table_name = command\n        table = TABLES[table_name]\n        return result if table.nil?\n\n        index = get_table_index(operator, value, 1, 6)\n\n        info = table.choice(index)\n        result = \"\#{info.table_name}:\#{info.value}:\#{info.body}\"\n\n        return result\n      end\n\n      def get_table_index(operator, value, dice_count, dice_type)\n        modify = 0\n\n        case operator\n        when \"+\"\n          modify = value\n        when \"-\"\n          modify = value * -1\n        end\n\n        index = @randomizer.roll_sum(dice_count, dice_type)\n        index += modify\n\n        index = [index, dice_count * 1].max\n        index = [index, dice_count * dice_type + 1].min\n\n        return index\n      end\n\n      TABLES = {\n        \"NTT\" => DiceTable::Table.new(\n          \"宝物表\",\n          \"1D6\",\n          [\n            \"金貨１枚\",\n            \"１ｄ６枚の金貨\",\n            \"２ｄ６枚の金貨（下限は金貨５枚）\",\n            \"１個のアクセサリー（１ｄ６×１ｄ６枚の金貨と同等の価値）\",\n            \"１個の宝石・小（１ｄ６×５枚の金貨と同等の価値。下限は金貨１５枚の価値）\",\n            \"１個の宝石・大（２ｄ６×５枚の金貨と同等の価値。下限は金貨３０枚の価値）\",\n            \"【魔法の宝物表】でダイスロールを行うこと。\",\n          ]\n        )\n      }.freeze\n\n      register_prefix('RH', 'D33', TABLES.keys)\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:RogueLikeHalf>", "initialize", "command", "self", "@sort_barabara_dice", "eval_game_system_specific_command", "$ret_or_1", "$ret_or_2", "resolute_action", "resolute_d33", "roll_table_command", "private", "with_symbol", "number", "0", ">", "to_s", "get_result_of_action", "total", "die", "target", "6", "Result", "critical", "1", "fumble", ">=", "success", "failure", "m", "match", "modify", "[]", "Arithmetic", "eval", "@round_type", "3", "to_i", "4", "@randomizer", "roll_once", "die_text", "+", "result", "command_text", "sequence", "text", "compact", "text=", "join", "dice", "roll_barabara", "2", "dice_text", "dice_total", "*", "12", "<", "p", "divmod", "[]=", "-", "10", "new", "upcase", "operator", "value", "get_another_table_result", "table_name", "table", "TABLES", "nil?", "index", "get_table_index", "info", "choice", "body", "dice_count", "dice_type", "-1", "roll_sum", "max", "min", "DiceTable::Table", "DiceTable", "freeze", "register_prefix", "keys", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,eAAL;QAGA,gCAAOA,WAAP;QAGA,oCAAWA,WAAX;QAGA,wCACNA,sCADqB,GAErBA,IAFqB,GAGrBA,yDAHqB,GAIrBA,IAJqB,GAKrBA,2BALqB,GAMrBA,IANqB,GAOrBA,+BAPqB,GAQrBA,IARqB,GASrBA,wBATM;;AAYAC,QAAAA,0BAAAA,sBAAeC,OAAfD;AAAAA,UAAAA;;UAAAA;;UACE,OAAAE,IAAA,EAAA,0DAAA,cAAA,EAAA,CAAMD,OAAN,CAAA,EAAA,IAAA;UAEAD,OAAAG,CAAAA,0BAAsB,IAAtBA;QAHFH,CAAAA;;AAMAI,QAAAA,iDAAAA,6CAAsCH,OAAtCG;AAAAA,UAAAA;;UACE,IAAA,QAAAC,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAJ,IAAAK,iBAAAA,CAAgBN,OAAhBM,CAAAD,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CACEJ,IAAAM,cAAAA,CAAaP,OAAbO,CADF,CAAA,CAAAH,CAAA,CAAA;YAAAD,OAAA;UAAA;YAEEA,OAAAF,IAAAO,oBAAAA,CAAmBR,OAAnBQ;UAFF;QADFL,CAAAA;QAMAF,IAAAQ,SAAAA,CAAAA;;AAEAC,QAAAA,2BAAAA,uBAAgBC,MAAhBD;AAAAA;UACE,IAAA,MAAGC,MAAH,EAAaC,CAAb,CAAA;YACE,OAAOF;UADT,OAEA,IAAA,QAAaG,OAAPF,MAAOE,EAAED,CAAFC,CAAb,CAAA;YACE,OAAQH,GAAD,GAAA,CAAIC,MAAJ;UADT;YAGE,OAAOA,MAAMG,MAAAA,CAAAA;UAHf;QAHFJ,CAAAA;;AAaAK,QAAAA,oCAAAA,gCAAyBC,KAAD,EAAQC,GAAR,EAAaC,MAArCH;AAAAA;UACE,IAAA,MAAGE,GAAH,EAAUE,CAAV,CAAA;YACE,OAAOC,YAAMC,UAAAA,CAAUN,QAAVM;UADf,OAEA,IAAA,MAAMJ,GAAN,EAAaK,CAAb,CAAA;YACE,OAAOF,YAAMG,QAAAA,CAAQR,OAARQ;UADf,OAEA,IAAA,QAAYC,OAANR,KAAMQ,EAAGN,MAAHM,CAAZ,CAAA;YACE,OAAOJ,YAAMK,SAAAA,CAASV,IAATU;UADf;YAGE,OAAOL,YAAMM,SAAAA,CAASX,IAATW;UAHf;QALFX,CAAAA;;AAYAT,QAAAA,+BAAAA,2BAAoBN,OAApBM,GAAAA,MAAAA,IAAAA,wCAAAA;AAAAA,UAAAA;;;UACEqB,IAAI,uBAAuBC,OAAAA,CAAO5B,OAAP4B;UAC3B,KAAA,QAAkBD,CAAlB,CAAA;YAAA,OAAO;UAAP;UAEAE,SAAS,CAAA,QAAAF,CAACG,OAAAA,CAACR,CAADQ,CAAD,CAAA,GAAA,CAAOC,gBAAUC,MAAAA,CAAML,CAACG,OAAAA,CAACR,CAADQ,CAAjB,EAAsBG,eAAZD,CAAjB,IAAA,CAA4CpB,CAA5C,CAAA;UACTM,SAASS,CAACG,OAAAA,CAACI,CAADJ,CAAGK,MAAAA,CAAAA;UACb,IAAA,MAAcjB,MAAd,EAAwBN,CAAxB,CAAA;YAAAM,SAASkB;UAAT;UAEAnB,MAAMoB,eAAWC,WAAAA,CAAWnB,CAAXmB;UACjBC,WAAWtB,GAAGH,MAAAA,CAAAA;UACdE,QAAYwB,SAAJvB,GAAIuB,E